import{_ as a,o,c as i,ag as l}from"./chunks/framework.ByAj6Cie.js";const p=JSON.parse('{"title":"Cómo funcionan los sistemas industriales","description":"","frontmatter":{},"headers":[],"relativePath":"es/concepts/how-industrial-systems-work.md","filePath":"es/concepts/how-industrial-systems-work.md"}'),n={name:"es/concepts/how-industrial-systems-work.md"};function r(s,e,t,c,d,m){return o(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="como-funcionan-los-sistemas-industriales" tabindex="-1">Cómo funcionan los sistemas industriales <a class="header-anchor" href="#como-funcionan-los-sistemas-industriales" aria-label="Permalink to &quot;Cómo funcionan los sistemas industriales&quot;">​</a></h1><h2 id="entendiendo-el-flujo" tabindex="-1">Entendiendo el flujo <a class="header-anchor" href="#entendiendo-el-flujo" aria-label="Permalink to &quot;Entendiendo el flujo&quot;">​</a></h2><p>Los sistemas industriales funcionan procesando continuamente información y energía para lograr un resultado deseado.</p><p>A nivel básico, todo sigue un ciclo:</p><ol><li>Medir</li><li>Decidir</li><li>Actuar</li><li>Repetir</li></ol><p>Este ciclo es la base de todos los sistemas automatizados.</p><hr><h2 id="el-lazo-de-control" tabindex="-1">El lazo de control <a class="header-anchor" href="#el-lazo-de-control" aria-label="Permalink to &quot;El lazo de control&quot;">​</a></h2><p>El núcleo de la mayoría de los sistemas industriales es el lazo de control.</p><p>Un lazo de control funciona así:</p><ol><li>Un sensor mide una condición del mundo real</li><li>La información se envía a un controlador</li><li>El controlador la compara con un valor deseado (setpoint)</li><li>Se toma una decisión</li><li>Un actuador ejecuta una acción</li><li>El sistema responde</li><li>El sensor vuelve a medir</li></ol><p>Este ciclo se ejecuta de forma continua.</p><hr><h2 id="lazo-abierto-vs-lazo-cerrado" tabindex="-1">Lazo abierto vs lazo cerrado <a class="header-anchor" href="#lazo-abierto-vs-lazo-cerrado" aria-label="Permalink to &quot;Lazo abierto vs lazo cerrado&quot;">​</a></h2><p>No todos los sistemas funcionan de la misma manera.</p><h3 id="lazo-abierto" tabindex="-1">Lazo abierto <a class="header-anchor" href="#lazo-abierto" aria-label="Permalink to &quot;Lazo abierto&quot;">​</a></h3><ul><li>No hay retroalimentación</li><li>El sistema actúa sin saber el resultado</li></ul><p>Ejemplo:</p><ul><li>Un motor que funciona por un tiempo fijo sin importar el resultado</li></ul><hr><h3 id="lazo-cerrado" tabindex="-1">Lazo cerrado <a class="header-anchor" href="#lazo-cerrado" aria-label="Permalink to &quot;Lazo cerrado&quot;">​</a></h3><ul><li>Utiliza retroalimentación</li><li>Se ajusta según las condiciones reales</li></ul><p>Ejemplo:</p><ul><li>Un sistema de control de temperatura que mantiene un valor definido</li></ul><p>Los sistemas de lazo cerrado son más precisos y confiables.</p><hr><h2 id="flujo-de-energia-e-informacion" tabindex="-1">Flujo de energía e información <a class="header-anchor" href="#flujo-de-energia-e-informacion" aria-label="Permalink to &quot;Flujo de energía e información&quot;">​</a></h2><p>En un sistema se mueven principalmente dos cosas:</p><h3 id="energia" tabindex="-1">Energía <a class="header-anchor" href="#energia" aria-label="Permalink to &quot;Energía&quot;">​</a></h3><p>Permite que el sistema funcione y realice trabajo.</p><p>Ejemplos:</p><ul><li>Energía eléctrica</li><li>Energía mecánica</li></ul><hr><h3 id="informacion" tabindex="-1">Información <a class="header-anchor" href="#informacion" aria-label="Permalink to &quot;Información&quot;">​</a></h3><p>Indica al sistema qué debe hacer.</p><p>Ejemplos:</p><ul><li>Señales de sensores</li><li>Lógica de control</li><li>Datos de comunicación</li></ul><hr><h2 id="la-importancia-del-tiempo" tabindex="-1">La importancia del tiempo <a class="header-anchor" href="#la-importancia-del-tiempo" aria-label="Permalink to &quot;La importancia del tiempo&quot;">​</a></h2><p>Los sistemas industriales no operan de forma aleatoria. El tiempo es crítico.</p><p>Los controladores (como los PLC) trabajan en ciclos:</p><ol><li>Leer entradas</li><li>Ejecutar lógica</li><li>Actualizar salidas</li></ol><p>Esto se conoce como ciclo de escaneo.</p><p>Un tiempo rápido y consistente asegura un funcionamiento estable.</p><hr><h2 id="ejemplo-sistema-de-control-de-temperatura" tabindex="-1">Ejemplo: sistema de control de temperatura <a class="header-anchor" href="#ejemplo-sistema-de-control-de-temperatura" aria-label="Permalink to &quot;Ejemplo: sistema de control de temperatura&quot;">​</a></h2><p>Un sistema simple funciona así:</p><ul><li>Un sensor mide la temperatura</li><li>El controlador la compara con un valor deseado</li><li>Si la temperatura es baja, se activa un calentador</li><li>Si la temperatura es alta, se apaga</li><li>El sistema se ajusta continuamente</li></ul><p>Este es un ejemplo clásico de lazo cerrado.</p><hr><h2 id="interaccion-entre-subsistemas" tabindex="-1">Interacción entre subsistemas <a class="header-anchor" href="#interaccion-entre-subsistemas" aria-label="Permalink to &quot;Interacción entre subsistemas&quot;">​</a></h2><p>Los sistemas industriales no están aislados.</p><p>Sus partes interactúan constantemente:</p><ul><li>La energía permite la operación</li><li>El control define el comportamiento</li><li>Los dispositivos de campo interactúan con la realidad</li><li>La comunicación conecta todo</li><li>Las interfaces permiten la interacción humana</li></ul><p>Entender estas interacciones es clave para entender el sistema.</p><hr><h2 id="error-comun" tabindex="-1">Error común <a class="header-anchor" href="#error-comun" aria-label="Permalink to &quot;Error común&quot;">​</a></h2><p>Un error común es enfocarse solo en los componentes.</p><p>Por ejemplo:</p><ul><li>Aprender qué es un PLC</li><li>Aprender qué es un motor</li></ul><p>Sin entender cómo trabajan juntos.</p><p>El entendimiento real viene de ver el sistema completo.</p><hr><h2 id="idea-clave" tabindex="-1">Idea clave <a class="header-anchor" href="#idea-clave" aria-label="Permalink to &quot;Idea clave&quot;">​</a></h2><p>Los sistemas industriales funcionan mediante ciclos continuos de:</p><ul><li>Medición</li><li>Procesamiento</li><li>Acción</li></ul><p>Todo está conectado y todo forma parte de un ciclo.</p>',67)])])}const h=a(n,[["render",r]]);export{p as __pageData,h as default};
